import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { TableCell, Radio, FormControl, InputLabel, Select, MenuItem, TextField, Button, IconButton } from '@material-ui/core';
import { ArrowDownward, Delete, Add } from '@material-ui/icons';
import { MyTable } from '../../../../../utils';
const style = theme => ({
    root: {
        
    },
    cell : {
        textAlign : "center"
    },
    grow : {
        display : "flex",
        flexGrow : 1,
    }
})
class _Packaging extends Component {
    constructor(props) {
        super(props);
        this.state = {
            tableData : [
                {defaultSU : true, package : "", product : true, quantity : 1},
            ],
            defaultSURow : null
        }
    }
    
    newRow = [
        {gap : true},
        {defaultSU : false, package: "", quantity : 0},
    ]
    addNewRow(count){
        count++;
        let {tableData} = this.state;
        tableData = [...tableData, ...this.newRow.map(item=>({...item, id : count}))]
        this.setState({tableData})
    }
    handleDefaultSUCheck = row => e => {
        const value= e.target.value;
        this.setState({defaultSURow : row.id})
    }
    deleteRow = id => () => {
        let {tableData} = this.state;
        tableData = tableData ? [...tableData] : [];
        for(let i = 0 ; i < 2; i++){
            const {index : dataIndex} = tableData.getFirstObjectByPropValue("id", id) || {};
            if(dataIndex){
                tableData.splice(dataIndex, 1);
            }
        }
        this.setState({tableData});
    }
    cellMapFormat = ({row, cellMap})=>{
        const {classes} = this.props;
        const {defaultSURow} = this.state;
        switch(cellMap){
            case "action" : 
                return <TableCell className={classes.cell}>
                    {!row.product && !row.gap && <IconButton onClick={this.deleteRow(row.id)}>
                        <Delete color="secondary"/>
                    </IconButton>}
                </TableCell>
            case "defaultSU" :
                return <TableCell className={classes.cell}>
                    {!row.gap && !row.product ?
                    <Radio
                        checked={defaultSURow === row.id}

                        onChange={this.handleDefaultSUCheck(row)}
                        /> : 
                    null}
                    </TableCell>
            case "package" : 
                return <TableCell className={classes.cell}>
                {row.gap ? 
                    <ArrowDownward/> :
                (row.product ?
                    "Product" :
                    <FormControl>
                        <InputLabel>Package</InputLabel>
                        <Select
                            style={{minWidth : 100}}
                            onChange={e=>{}}
                            value={row[cellMap]}>
                            <MenuItem value={1}>options</MenuItem>
                        </Select>
                    </FormControl>)}
                </TableCell>
            case "quantity" :
                return <TableCell className={classes.cell}>
                    {!row.product && !row.gap ? <TextField
                        type="number"
                        style={{width : 50}}/> : 
                        row[cellMap]}
                </TableCell>
            default : return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
    render() {
        const {classes} = this.props;
        const {tableData} = this.state;
        return (
            <div className={classes.root}>
                <MyTable
                    title={
                    <FormControl style={{display : "flex", flexDirection : "row", margin : 10}}>
                        Packaging
                        <div className={classes.grow}/>
                        <IconButton onClick={()=>this.addNewRow(tableData ? tableData.length : 0)}>
                            <Add/>
                        </IconButton>
                    </FormControl>} 
                    titleProps={{
                        style : {
                            textAlign : "left"
                        }
                    }}                   
                    classes={{tableHeader : classes.cell}}
                    header={["Default Selling Unit", "Packages", "Quantity", "Action"]}
                    dataMap={["defaultSU", "package", "quantity", "action"]}
                    data={tableData}
                    CellMap={this.cellMapFormat.bind(this)}
                    />
            </div>
        );
    }
}
_Packaging.propTypes = {
    classes : PropTypes.object.isRequired
};
export const Packaging = withStyles(style)(_Packaging);