import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyCustomTabs, headerActions, breadCrumbActions, mainStageHeaderAction, headerStrings } from "../../../utils";
import { routeNamesInventory } from '../../../routeNames';
import { NewItemInfo } from './INVNewProductInfo';
import { ItemVariants } from './ItemVariants';


const style = theme => ({
    root: {
    }
})
let variants = [
    {
        _id : 1,
        name : "Appearance",
        options : [
            {
                _id : 1, 
                name : "color", 
                values : [
                    {_id : 1, name : "red"},
                ]
            }
        ]
    }
]
class _INVNewProduct extends Component {
    constructor(props) {
        super(props);
        this.state = {
            tabValue : null
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "NEW ITEM",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        breadCrumbActions.addToBreadCrumb([
            {name : "New Item", path : routeNamesInventory.newItem},
        ])(dispatch);
        mainStageHeaderAction({})(dispatch);
    }
    render() {
        const {classes} = this.props;
        const {tabValue } = this.state;
        return (
            <div className={classes.root}>
                <MyCustomTabs
                    getInitialTabValue={tabValue => this.setState({tabValue})}
                    position="sticky"
                    tabs={{
                        info : "Info",
                        variants : "Variants",
                    }}
                    />
                <div style={{marginTop : 20}}>
                    {tabValue === "info" && <NewItemInfo
                        variants={variants}/>}
                    {tabValue === "variants" && <ItemVariants
                        variants={variants}/>}                    
                </div>
            </div>
        );
    }
}


_INVNewProduct.propTypes = {
    classes : PropTypes.object.isRequired,
};
const mapStateToProps = state => ({
    state
})


export const INVNewProduct = connect(mapStateToProps)(withStyles(style)(_INVNewProduct));
export {INVNewProduct as default}