const style = theme => ({
    root: {
        marginTop : 30
    }
})
class _NewItemInfo extends Component {
    constructor(props) {
        super(props);
        
        this.initialiseComponent();
    }
    initialiseComponent(){
        const {
            [invProductStrings.productDescriptions] : productDescriptions,
            dispatch,
        } = this.props;
        if(!productDescriptions)
            invProductActions.getProductDescriptions()(dispatch);
    }
    render() {
        const {
            classes, variants,
            [invProductStrings.productDescriptions] : descriptions
        } = this.props;
        console.log(this.variantcontext);
        return (
            <div className={classes.root}>
                <FormDisplay
                    formConfig={formConfig}
                    getContext={context=>this.formContext=context}
                    />
                <Packaging/>
                <Description
                    title="Descriptions"
                    descriptions={descriptions}
                    getContext={context=>this.descriptionContext = context}/>
                <Variants
                    title="Variants"
                    variants={variants}
                    getContext={context=>this.variantcontext=context}/>
            </div>
        );
    }
}


_NewItemInfo.propTypes = {
    classes : PropTypes.object.isRequired,
    variants : PropTypes.array,
};
const mapStateToProps = ({invProductReducer}) => ({
    [invProductStrings.productDescriptions] : invProductReducer[invProductStrings.productDescriptions],

})


export const NewItemInfo = connect(mapStateToProps)(withStyles(style)(_NewItemInfo));
export {NewItemInfo as default}